r_mwa_finance_payment_day_nest_emer.sql:
select ta.loan_type, ta.loan_type_description as "ประเภท", count(loan_type) as count_type ,sum(principal_amount) as sum_principal ,sum(interest_amount) as sum_interest from ( select sc_lon_m_rule.loan_type, sc_lon_m_rule.loan_type_description, sc_lon_m_loan_card.loan_code, sc_com_m_receipt_item.principal_amount, sc_com_m_receipt_item.interest_amount from sc_com_m_receipt, sc_com_m_receipt_item, sc_com_m_ucf_receipt_item_type, sc_lon_m_rule, sc_lon_m_loan_card where sc_com_m_receipt.receipt_no = sc_com_m_receipt_item.receipt_no and sc_com_m_ucf_receipt_item_type.item_type_id = sc_com_m_receipt_item.item_type_id and sc_com_m_receipt_item.loan_type = sc_lon_m_rule.loan_type and sc_com_m_receipt_item.description = sc_lon_m_loan_card.loan_contract_no and sc_lon_m_rule.loan_group_code = {1} and sc_com_m_receipt_item.item_amount > 0 and sc_com_m_ucf_receipt_item_type.group_item = 'LON' and sc_lon_m_rule.loan_type not in ( 'รก') and sc_com_m_receipt.receipt_date between '!receipt_date_1!' and '!receipt_date_2!' and sc_com_m_receipt.receipt_status = '0' and sc_com_m_receipt.money_type_id not in ( 'TBK' , 'CLR' , 'AOP' ,'TRL' , 'FUN' , 'CRC') and sc_lon_m_loan_card.loan_code = '0' --เอาแค่ลูกหนี้ปกติ
/*and ('!receipt_mode!' = 'F' and sc_com_m_receipt.receipt_mode = 'F' or '!receipt_mode!' = 'R' and sc_com_m_receipt.receipt_mode = 'R' or '!receipt_mode!' is null and sc_com_m_receipt.receipt_mode not in('F','R'))*/
/*WHERE*/ -- and sc_com_m_receipt_item.loan_type = '!loan_type!' -- and ( '!loan_type!' is null or sc_com_m_receipt_item.loan_type = '!loan_type!' )
and ('!loan_type!' is null or exists(select null from sc_lon_m_contract where sc_lon_m_contract.loan_contract_no = sc_com_m_receipt.loan_contract_no and sc_lon_m_contract.loan_type ='!loan_type!'))
)ta group by ta.loan_type , ta.loan_type_description, ta.loan_code order by ta.loan_type , ta.loan_type_description, ta.loan_code

r_mwa_finance_payment_day_nest_sum_balan.sql:
select sc_lon_m_loan_card.loan_type, count( sc_lon_m_loan_history.loan_contract_no ) as sub_count, sum(sc_lon_m_loan_history.principal_of_loan) as principal_of_loan , sum(sc_lon_m_loan_history.interest_amount) as interest_amount from sc_lon_m_loan_history ,sc_lon_m_loan_card ,sc_lon_m_rule ,sc_com_m_receipt where sc_com_m_receipt.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_history.loan_contract_no = sc_lon_m_loan_card.loan_contract_no and sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type and sc_lon_m_rule.loan_type not in ( 'รก') and sc_lon_m_rule.loan_group_code = '01' and ( sc_lon_m_loan_card.loan_code = null or sc_lon_m_loan_card.loan_code = '0' ) --*เอาเฉพาะสัญญาปกติ and sc_com_m_receipt.receipt_date between '!receipt_date_1!' and '!receipt_date_2!' and sc_com_m_receipt.receipt_status = '0' and sc_com_m_receipt.money_type_id not in ( 'TBK' , 'CLR' , 'AOP' ,'TRL' , 'FUN' , 'CRC' )
/*and ('!receipt_mode!' = 'F' and sc_com_m_receipt.receipt_mode = 'F' or '!receipt_mode!' = 'R' and sc_com_m_receipt.receipt_mode = 'R' or '!receipt_mode!' is null and sc_com_m_receipt.receipt_mode not in('F','R'))*/
/*WHERE*/ group by sc_lon_m_loan_card.loan_code,sc_lon_m_loan_card.loan_type order by sc_lon_m_loan_card.loan_code,sc_lon_m_loan_card.loan_type

select sc_lon_m_loan_card.loan_type, count( sc_lon_m_loan_history.loan_contract_no ) as sub_count, sum(sc_lon_m_loan_history.principal_balance_of_loan) as principal_balance_of_loan, sum(sc_lon_m_loan_history.interest_amount) as interest_amount from sc_lon_m_loan_history ,sc_lon_m_loan_card ,sc_lon_m_rule ,sc_com_m_receipt where sc_com_m_receipt.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_history.loan_contract_no = sc_lon_m_loan_card.loan_contract_no and sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type and sc_lon_m_rule.loan_group_code = '01' and sc_lon_m_rule.loan_type not in ( 'รก') and ( sc_lon_m_loan_card.loan_code = null or sc_lon_m_loan_card.loan_code = '0' ) --*เอาเฉพาะสัญญาปกติ and sc_com_m_receipt.receipt_date between '!receipt_date_1!' and '!receipt_date_2!' and sc_com_m_receipt.receipt_status = '0' and sc_com_m_receipt.money_type_id not in ( 'TBK' , 'CLR' , 'AOP' ,'TRL' , 'FUN' , 'CRC' , 'CRC') and sc_lon_m_loan_history.clear_focus = '1'
/*and ('!receipt_mode!' = 'F' and sc_com_m_receipt.receipt_mode = 'F' or '!receipt_mode!' = 'R' and sc_com_m_receipt.receipt_mode = 'R' or '!receipt_mode!' is null and sc_com_m_receipt.receipt_mode not in('F','R'))*/
/*WHERE*/ group by sc_lon_m_loan_card.loan_code,sc_lon_m_loan_card.loan_type order by sc_lon_m_loan_card.loan_code,sc_lon_m_loan_card.loan_type

r_mwa_finance_payment_day_nest_fund.sql:
select sc_lon_m_loan_card.loan_type, count( sc_lon_m_loan_history.loan_contract_no ) as sub_count, sum(sc_lon_m_loan_history.principal_balance_of_loan) as principal_balance_of_loan, sum(sc_lon_m_loan_history.interest_amount) as interest_amount from sc_lon_m_loan_history ,sc_lon_m_loan_card ,sc_lon_m_rule ,sc_com_m_receipt where sc_com_m_receipt.membership_no = sc_lon_m_loan_card.membership_no and sc_lon_m_loan_history.loan_contract_no = sc_lon_m_loan_card.loan_contract_no and sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type and sc_lon_m_rule.loan_type = 'ภภ' and sc_lon_m_rule.loan_group_code = '01' and sc_lon_m_rule.loan_type not in ( 'รก') and ( sc_lon_m_loan_card.loan_code = null or sc_lon_m_loan_card.loan_code = '0' ) --*เอาเฉพาะสัญญาปกติ and sc_com_m_receipt.receipt_date between '!receipt_date_1!' and '!receipt_date_2!' and sc_com_m_receipt.receipt_status = '0' and sc_com_m_receipt.money_type_id not in ( 'TBK' , 'CLR' , 'AOP' ,'TRL' ,'FUN' , 'CRC' )
/*and ('!receipt_mode!' = 'F' and sc_com_m_receipt.receipt_mode = 'F' or '!receipt_mode!' = 'R' and sc_com_m_receipt.receipt_mode = 'R' or '!receipt_mode!' is null and sc_com_m_receipt.receipt_mode not in('F','R'))*/
/*WHERE*/ group by sc_lon_m_loan_card.loan_code,sc_lon_m_loan_card.loan_type order by sc_lon_m_loan_card.loan_code,sc_lon_m_loan_card.loan_type
